   152	        let token_hash = token_hash.to_string();
   153	        self.read(move |catalog| {
   154	            for repo in catalog.repositories.values() {
   155	                if let Some(invite) = repo
   156	                    .invitations
   157	                    .iter()
   158	                    .find(|invite| invite.token_hash == token_hash)
