   170	        user: UserAccount,
   171	        now_unix: u64,
   172	    ) -> Result<(crate::domain::store::StoredRepository, RepositoryMember), ApiError> {
   173	        let token_hash = token_hash.to_string();
   174	        match self.inner.as_ref() {
   175	            MetadataStoreInner::Postgres { db, runtime } => {
   176	                let db = Arc::clone(db);
   177	                run_api_db_on(runtime, async move {
   178	                    let tx = db.as_ref().begin().await.map_err(ApiError::internal)?;
   179	                    acquire_metadata_write_lock(&tx).await?;
   180	                    let invite = entities::repository_invite::Entity::find()
   181	                        .filter(
   182	                            entities::repository_invite::Column::TokenHash.eq(token_hash.clone()),
   183	                        )
   184	                        .one(&tx)
   185	                        .await
   186	                        .map_err(ApiError::internal)?
   187	                        .ok_or_else(|| ApiError::not_found("repository invite not found"))?;
   188	                    let row = entities::repository::Entity::find_by_id(invite.repo_id)
   189	                        .one(&tx)
   190	                        .await
   191	                        .map_err(ApiError::internal)?
   192	                        .ok_or_else(|| ApiError::not_found("repository invite not found"))?;
   193	                    let mut repo = repository_from_model(&tx, row).await?;
   194	                    let outcome =
   195	                        accept_repository_invite(&mut repo, &user, &token_hash, now_unix)?;
   196	                    save_repo_mutation(&tx, &repo, &mutation_effects_none()).await?;
   197	                    let result = match outcome {
   198	                        AcceptRepositoryInviteOutcome::Accepted(member) => Ok((repo, member)),
   199	                        AcceptRepositoryInviteOutcome::Expired => {
   200	                            Err(ApiError::conflict("repository invite expired"))
   201	                        }
   202	                    };
   203	                    tx.commit().await.map_err(ApiError::internal)?;
   204	                    result
   205	                })
   206	            }
   207	            #[cfg(any(test, feature = "memory-metadata"))]
   208	            MetadataStoreInner::Memory(_) => {
   209	                let (repo, outcome) = self.update(move |catalog| {
   210	                    let repo_id = catalog
   211	                        .repositories
   212	                        .values()
   213	                        .find(|repo| {
   214	                            repo.invitations
   215	                                .iter()
   216	                                .any(|invite| invite.token_hash == token_hash)
