   221	pub(crate) async fn update_file_visibility(
   222	    State(state): State<AppState>,
   223	    headers: HeaderMap,
   224	    Path((owner, repo_name)): Path<(String, String)>,
   225	    Json(input): Json<UpdateFileVisibilityRequest>,
   226	) -> Result<Json<Vec<RepoFileResponse>>, ApiError> {
   227	    let user = optional_scope_user(&state, &headers).await?;
   228	    let update_paths = parse_visibility_paths(&input.paths)?;
   229	    let visibility = input.visibility;
   230	    let repo = find_repo(&state, &owner, &repo_name)?;
   231	    let principal = user
   232	        .as_ref()
   233	        .map(|user| principal_for_user_id(&repo, &user.id))
   234	        .unwrap_or_else(Principal::public);
   235	    ensure_repo_read(&state, &repo, &principal)?;
   236	    if !repo
   237	        .access_for_principal(&principal)
   238	        .can_change_file_visibility
   239	    {
   240	        return Err(ApiError::forbidden("file visibility permission required"));
   241	    }
   242	
   243	    let owner_files = files_for_visibility_update(&repo, &principal)?;
   244	    for path in &update_paths {
   245	        let selected_file = owner_files
   246	            .iter()
   247	            .find(|file| file.path == path.as_str())
   248	            .ok_or_else(|| ApiError::not_found(format!("file {} not found", path.as_str())))?;
   249	        if visibility == Visibility::Public && !selected_file.tracked {
   250	            return Err(ApiError::bad_request(format!(
   251	                "file {} must be tracked by Git before it can be made public",
   252	                path.as_str()
   253	            )));
   254	        }
   255	    }
   256	
   257	    let user_id = user
   258	        .as_ref()
   259	        .map(|user| user.id.clone())
   260	        .ok_or_else(|| ApiError::forbidden("owner role required"))?;
   261	    let updated = state.metadata.update_repo_file_visibility(
   262	        &owner,
   263	        &repo_name,
   264	        &user_id,
   265	        update_paths,
   266	        visibility,
   267	    )?;
   268	    state.publish_repo_change(
   269	        &updated.record.id,
   270	        updated.record.change_version,
   271	        "visibility-changed",
   272	    );
   273	
   274	    let principal = Principal {
   275	        id: user_id,
   276	        kind: crate::domain::policy::PrincipalKind::User,
   277	    };
   278	    let updated_files = files_for_visibility_update(&updated, &principal)?;
   279	
   280	    Ok(Json(updated_files))
   281	}
