   283	fn parse_visibility_paths(paths: &[String]) -> Result<Vec<ScopePath>, ApiError> {
   284	    if paths.is_empty() {
   285	        return Err(ApiError::bad_request("at least one file path is required"));
   286	    }
   287	
   288	    let mut parsed = BTreeSet::new();
   289	    for path in paths {
   290	        parsed.insert(ScopePath::parse(path).map_err(ApiError::bad_request)?);
   291	    }
   292	
   293	    Ok(parsed.into_iter().collect())
   294	}
